// Rename attachment_0 to data for PDF Vector compatibility
const items = $input.all();

for (const item of items) {
  if (item.binary && item.binary.attachment_0) {
    item.binary.data = item.binary.attachment_0;
    delete item.binary.attachment_0;
  }
}

return items;

const candidate = ($input.first().json?.data || $input.first().json) || {};
const emailData = $('Gmail Trigger').item.json;

const requiredSkills = [
  'javascript', 'python', 'react', 'node', 'sql',
  'api', 'git', 'aws', 'docker', 'typescript'
];

// Experience scoring (40 pts)
let expScore = 0;
const years = parseFloat(candidate.yearsOfExperience) || 0;
if (years >= 7)      expScore = 40;
else if (years >= 5) expScore = 35;
else if (years >= 3) expScore = 25;
else if (years >= 1) expScore = 15;
else                 expScore = 5;

// Education scoring (30 pts)
let eduScore = 10;
const degree = (candidate.highestDegree || '').toLowerCase();
if (degree.includes('phd') || degree.includes('doctorate'))    eduScore = 30;
else if (degree.includes('master') || degree.includes('mba'))  eduScore = 25;
else if (degree.includes('bachelor'))                           eduScore = 20;

// Skills matching (30 pts)
const skillsStr = (candidate.technicalSkillsList || '').toLowerCase();
let skillsMatched = 0;
requiredSkills.forEach(skill => { if (skillsStr.includes(skill)) skillsMatched++; });
const skillsScore = Math.min(skillsMatched * 3, 30);

const totalScore = expScore + eduScore + skillsScore;
let status = 'Pass';
if (totalScore >= 75)      status = 'Schedule Interview';
else if (totalScore >= 50) status = 'Review Further';

return [{ json: {
  fullName:           candidate.fullName           || 'Unknown',
  email:              candidate.email              || '',
  phone:              candidate.phone              || 'N/A',
  location:           candidate.location           || 'N/A',
  currentTitle:       candidate.currentTitle       || 'N/A',
  yearsOfExperience:  years,
  mostRecentCompany:  candidate.mostRecentCompany  || 'N/A',
  highestDegree:      candidate.highestDegree      || 'N/A',
  educationField:     candidate.educationField     || 'N/A',
  skillsList:         candidate.technicalSkillsList || '',
  certificationsList: candidate.certificationsList || 'N/A',
  keyAchievements:    candidate.keyAchievements    || 'N/A',
  applicantEmail: emailData?.from?.value?.[0]?.address || candidate.email || 'unknown',
  applicationDate: emailData?.date || new Date().toISOString(),
  score: totalScore,
  expScore, eduScore, skillsScore,
  skillsMatched,
  status,
  processedAt: new Date().toISOString()
}}];

